async function seedLinkedinTemplates() {
  const existing = await db.select({ id: linkedinTemplates.id }).from(linkedinTemplates).limit(1);
  if (existing.length > 0) {
    console.log('LinkedIn templates already seeded, skipping');
    process.exit(0);
  }

  const batchSize = 50;
  let inserted = 0;
  for (let i = 0; i < TEMPLATES.length; i += batchSize) {
    const batch = TEMPLATES.slice(i, i + batchSize);
    await db.insert(linkedinTemplates).values(batch).onConflictDoNothing();
    inserted += batch.length;
    console.log(`Inserted ${inserted}/${TEMPLATES.length} templates`);
  }

  console.log('LinkedIn template seed complete');
  process.exit(0);
}

seedLinkedinTemplates().catch(err => {
  console.error(err);
  process.exit(1);
});
